SELECT [Sales Header].[Document Type], [Sales Header].No_, [Sales Header].[Sell-to Customer No_], [Sales Header].[Bill-to Customer No_], [Sales Header].[Bill-to Name], [Sales Header].[payment method code], [Customer Bank Account].[Customer No_], [Customer Bank Account].Code, [Customer Bank Account].Name, [Sales Header].[Bank Account], Customer.[old febos no_], Customer.[old bridge no_], [Customer Bank Account].ABI, [Customer Bank Account].CAB, [Customer Bank Account].IBAN
FROM ([Sales Header] LEFT JOIN [Customer Bank Account] ON ([Sales Header].[Bill-to Customer No_] = [Customer Bank Account].[Customer No_]) AND ([Sales Header].[Bank Account] = [Customer Bank Account].Code)) LEFT JOIN Customer ON [Sales Header].[Bill-to Customer No_] = Customer.No_
WHERE ((([Sales Header].[Document Type])=1) AND (([Sales Header].[payment method code])="RIBA") AND (([Customer Bank Account].[Customer No_]) Is Null) AND (([Sales Header].[Bank Account])<>"" And ([Sales Header].[Bank Account]) Is Not Null)) OR ((([Sales Header].[Document Type])=1) AND (([Sales Header].[payment method code])="RIBA") AND (([Customer Bank Account].[Customer No_]) Is Not Null) AND (([Customer Bank Account].ABI)="")) OR ((([Sales Header].[Document Type])=1) AND (([Sales Header].[payment method code])="RIBA") AND (([Customer Bank Account].[Customer No_]) Is Not Null) AND (([Customer Bank Account].CAB)=""));

